var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_CHUSEOK","text":{"KOREA":"내가 부사령관님을 따르는 줄 알면서도 그런 제안을 하다니......","JPN":"私が副司令官に従うことを知りつつ、そんな提案をするとは……","ENG":"You're making this offer even though you know I'm following the Deputy Commander.","TWN":"明知我聽從副司令官，還提出這樣的提議……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_CHUSEOK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_CHUSEOK","text":{"KOREA":"대담한 건지 어리석은 건지 모르겠군.","JPN":"大胆なのか、愚かなのか。","ENG":"I don't know if you're bold or foolish.","TWN":"不知是大膽還是愚笨。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_CHUSEOK","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_CHUSEOK","text":{"KOREA":"지저분한 농담이라고 해도, 날 일개 직원으로 취급하는 듯한 네 태도가 썩 마음에 들진 않아.","JPN":"冗談だとしても私を下っ端の社員のように扱うお前の態度が気に食わない。","ENG":"Even if you're just teasing, I don't like that you treat me as if I'm one of your employees.","TWN":"即使是亂七八糟的玩笑，你對待我的態度也不太滿意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_CHUSEOK","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_CHUSEOK","text":{"KOREA":"하지만 너에게는 다행이겠군. 난 고작 그런 것에 연연할 만큼 속이 좁진 않으니 말이야.","JPN":"だが、よかったな。私はそんな細かいことを気にするほど心は狭くない。","ENG":"But luckily for you, I'm not so narrow-minded that I'd let something like that bother me.","TWN":"但是對你來說真是萬幸。我並不是個心胸狹窄的人，對於那種瑣事，我是不會在乎的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_CHUSEOK","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_CHUSEOK","text":{"KOREA":"네가 그간 보여 줬던 모습들은......","JPN":"今までお前が見せてくれた姿は……","ENG":"What you've presented to me so far...","TWN":"你在這段期間表現的樣子....."},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_CHUSEOK","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_CHUSEOK","text":{"KOREA":"일부러 드러내던 빈틈을 제외하면, 아슬아슬하게 합격점이었어.","JPN":"わざとさらけ出していた隙を除けば、ギリギリ合格だった。","ENG":"meets my standards, though barely, except for those fake weaknesses you showed.","TWN":"除了故意暴露的漏洞外，勉强合格了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_CHUSEOK","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_CHUSEOK","text":{"KOREA":"부사령관님께는 미치지 못해도, 너에게도 사람을 이끄는 자질이 있다는 건 인정해 주지.","JPN":"副司令官には及ばないが、お前にも統率力があることは認めてやる。","ENG":"You're nowhere near as good as the Deputy Commander, but you do have leadership. I'll give you that.","TWN":"雖然不及副司令官，但你也有領導人的資質，這是可以肯定的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_CHUSEOK","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_CHUSEOK","text":{"KOREA":"그러니 복종이 아닌 칭찬의 의미로, 네 제안을 수락하겠다.","JPN":"だから服従ではなく称賛の意味で、\\nお前の提案を承諾しよう。","ENG":"So, I accept your offer. As a way of praising you; not submitting to you.","TWN":"所以我接受你的提議，而不是服從。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_CHUSEOK","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_CHUSEOK","text":{"KOREA":"자, 조금은 기뻐해도 좋아.","JPN":"さぁ、少しは喜べ。","ENG":"Now, show me how happy you are.","TWN":"來，可以高興一點也沒關係。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_CHUSEOK","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};